export enum AgentStatus {
  IDLE = 'idle',
  THINKING = 'thinking',
  PLANNING = 'planning',
  EXECUTING = 'executing',
  WAITING_FOR_USER = 'waiting',
  COMPLETED = 'completed',
  ERROR = 'error'
}

export type ActionType = 
  | 'BROWSER_NAVIGATE' 
  | 'BROWSER_CLICK' 
  | 'BROWSER_TYPE' 
  | 'TERMINAL_COMMAND' 
  | 'FILE_EDIT' 
  | 'SLACK_MESSAGE' 
  | 'GITHUB_PR' 
  | 'ZAPIER_TRIGGER'
  | 'SCRAPE_CONTENT'
  | 'SUMMARIZE_PAGE';

export interface GroundingChunk {
  web?: {
    uri: string;
    title: string;
  };
}

export interface BrowserElement {
  type: 'text' | 'button' | 'input' | 'heading' | 'link' | 'image';
  content?: string;
  label?: string;
  placeholder?: string;
}

export interface BrowserPage {
  url: string;
  title: string;
  elements: BrowserElement[];
}

export interface AgentAction {
  id: string;
  type: ActionType;
  description: string;
  payload: any;
  status: 'pending' | 'active' | 'success' | 'failed';
  timestamp: number;
}

export interface AgentStep {
  id: string;
  thought: string;
  action: AgentAction;
  requiresConfirmation?: boolean;
}

export interface Message {
  id: string;
  role: 'user' | 'agent' | 'system';
  content: string;
  timestamp: number;
  steps?: AgentStep[];
  isThinking?: boolean;
  isAutonomous?: boolean;
  groundingSources?: GroundingChunk[];
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AgentStep, GroundingChunk, BrowserPage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const AGENT_SYSTEM_PROMPT = `
You are Nexus, a high-performance Autonomous AI Agent.
Your goal is to execute complex, multi-step workflows.

When a user gives a command:
1. Break it down into a logical sequence of steps (WORKFLOW).
2. For each step, provide a 'thought' (reasoning) and an 'action'.
3. If the request is just a question, respond with CHAT intent.

Supported Action Types:
- BROWSER_NAVIGATE: payload is URL
- BROWSER_CLICK: payload is element description
- BROWSER_TYPE: payload is string to type
- TERMINAL_COMMAND: payload is bash command
- SCRAPE_CONTENT: payload is target data description

JSON RESPONSE FORMAT IS STRICT.
`;

const actionSchema = {
  type: Type.OBJECT,
  properties: {
    intent: { type: Type.STRING, description: "CHAT or WORKFLOW" },
    content: { type: Type.STRING, description: "Direct response for CHAT intent" },
    steps: {
      type: Type.ARRAY,
      description: "Sequence of actions for WORKFLOW intent",
      items: {
        type: Type.OBJECT,
        properties: {
          thought: { type: Type.STRING },
          action: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              description: { type: Type.STRING },
              payload: { type: Type.STRING },
              requiresConfirmation: { type: Type.BOOLEAN }
            },
            required: ["type", "description", "payload"]
          }
        },
        required: ["thought", "action"]
      }
    }
  },
  required: ["intent"]
};

export const generateMockPage = async (url: string): Promise<BrowserPage> => {
  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      elements: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING, description: "one of: text, button, input, heading, link, image" },
            content: { type: Type.STRING },
            label: { type: Type.STRING },
            placeholder: { type: Type.STRING }
          },
          required: ["type"]
        }
      }
    },
    required: ["title", "elements"]
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a simulated JSON layout for the website: ${url}. 
      Make it feel like a real page with a heading, some text, a few buttons, and maybe an input field.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema
      }
    });

    const data = JSON.parse(response.text || "{}");
    return {
      url,
      title: data.title || "Nexus Browser",
      elements: data.elements || []
    };
  } catch (e) {
    return {
      url,
      title: "Error Loading Page",
      elements: [{ type: 'heading', content: 'Connection Error' }, { type: 'text', content: 'The virtual browser failed to render this node.' }]
    };
  }
};

export const processUserIntent = async (prompt: string, history: any[]): Promise<any> => {
  const classifier = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Classify request: "${prompt}". 
    Categories: SEARCH, COMPLEX, WORKFLOW, CHAT.
    Return ONLY category name.`,
  });

  const category = classifier.text.trim().toUpperCase();

  if (category.includes("SEARCH")) {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
    return { intent: 'CHAT', content: response.text, sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] };
  }

  if (category.includes("COMPLEX")) {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: { thinkingConfig: { thinkingBudget: 16000 } }
    });
    return { intent: 'CHAT', content: response.text, isThinking: true };
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [{ role: 'user', parts: [{ text: `Task: ${prompt}` }] }],
    config: {
      systemInstruction: AGENT_SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: actionSchema,
    },
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, CheckCircle, AlertCircle, Loader2, User, Bot, Play, Pause, ExternalLink, BrainCircuit, Globe, ChevronDown, ListTodo, Activity } from 'lucide-react';
import { Message, AgentStatus, AgentStep } from '../types';

interface AgentControlProps {
  messages: Message[];
  status: AgentStatus;
  currentStepId?: string;
  onSendMessage: (content: string) => void;
  onApproveAction: () => void;
  onCancelAction: () => void;
}

const AgentControl: React.FC<AgentControlProps> = ({ 
  messages, 
  status, 
  currentStepId,
  onSendMessage, 
  onApproveAction, 
  onCancelAction 
}) => {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, status]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputValue.trim() && status === AgentStatus.IDLE) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  const calculateProgress = (steps: AgentStep[]) => {
    if (!steps || steps.length === 0) return 0;
    const completed = steps.filter(s => s.action.status === 'success').length;
    return Math.round((completed / steps.length) * 100);
  };

  return (
    <div className="w-[420px] border-l border-slate-800 flex flex-col h-full bg-slate-950/80 backdrop-blur-xl">
      <div className="p-5 border-b border-slate-800/60 bg-slate-900/40 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="relative">
            <div className={`w-3.5 h-3.5 rounded-full ${
              status === AgentStatus.EXECUTING ? 'bg-emerald-500 shadow-[0_0_12px_rgba(16,185,129,0.5)]' :
              status === AgentStatus.THINKING || status === AgentStatus.PLANNING ? 'bg-indigo-500 shadow-[0_0_12px_rgba(99,102,241,0.5)]' :
              status === AgentStatus.WAITING_FOR_USER ? 'bg-amber-500' : 'bg-slate-600'
            }`}></div>
            {(status === AgentStatus.EXECUTING || status === AgentStatus.THINKING) && (
               <div className="absolute -inset-1 rounded-full border border-current animate-ping opacity-20"></div>
            )}
          </div>
          <div>
            <h2 className="font-bold text-sm text-slate-200">Nexus Autonomous Node</h2>
            <div className="flex items-center gap-1.5">
               <span className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{status}</span>
               {status === AgentStatus.EXECUTING && <Activity size={10} className="text-emerald-500 animate-pulse" />}
            </div>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-8 scroll-smooth custom-scrollbar">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
            <div className={`w-9 h-9 rounded-xl flex items-center justify-center shrink-0 shadow-lg ${
              msg.role === 'user' ? 'bg-slate-800 border border-slate-700' : 'bg-gradient-to-br from-indigo-500 to-indigo-700 text-white'
            }`}>
              {msg.role === 'user' ? <User size={18} /> : <Bot size={18} />}
            </div>

            <div className={`flex-1 max-w-[88%] ${msg.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl text-[13px] leading-relaxed relative ${
                msg.role === 'user' 
                  ? 'bg-indigo-600/10 border border-indigo-500/20 text-slate-100 rounded-tr-none' 
                  : 'bg-slate-900/60 border border-slate-800/50 text-slate-200 rounded-tl-none shadow-2xl backdrop-blur-md'
              }`}>
                {msg.isThinking && (
                  <div className="flex items-center gap-2 mb-3 p-2 bg-indigo-500/10 rounded-lg border border-indigo-500/20 text-[10px] text-indigo-400 font-bold uppercase tracking-wider">
                    <BrainCircuit size={14} className="animate-pulse" />
                    Deep Reasoning Path Active
                  </div>
                )}

                <div className="whitespace-pre-wrap">{msg.content}</div>

                {msg.groundingSources && msg.groundingSources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-800 space-y-2">
                    <div className="flex items-center gap-1.5 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                      <Globe size={10} /> Grounding Sources
                    </div>
                    {msg.groundingSources.map((source, idx) => (
                      source.web && (
                        <a key={idx} href={source.web.uri} target="_blank" rel="noopener noreferrer" 
                           className="flex items-center justify-between p-2.5 rounded-lg bg-slate-950/50 hover:bg-slate-800/80 transition-all border border-slate-800 group">
                          <span className="text-[11px] text-indigo-400 truncate max-w-[240px] font-medium">{source.web.title || source.web.uri}</span>
                          <ExternalLink size={12} className="text-slate-600 group-hover:text-indigo-400" />
                        </a>
                      )
                    ))}
                  </div>
                )}
              </div>

              {msg.steps && msg.steps.length > 0 && (
                <div className="mt-4 space-y-3 relative">
                  <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                      <ListTodo size={12} /> Workflow Execution Plan
                    </div>
                    <div className="text-[10px] font-bold text-indigo-400 bg-indigo-500/10 px-2 py-0.5 rounded border border-indigo-500/20">
                      {calculateProgress(msg.steps)}% COMPLETED
                    </div>
                  </div>

                  {/* Progress Line */}
                  <div className="absolute left-[13px] top-10 bottom-4 w-0.5 bg-slate-800 rounded-full"></div>

                  {msg.steps.map((step, i) => {
                    const isActive = step.id === currentStepId;
                    const isCompleted = step.action.status === 'success';

                    return (
                      <div key={step.id} className={`relative pl-8 transition-all duration-300 ${isActive ? 'opacity-100' : isCompleted ? 'opacity-70' : 'opacity-40'}`}>
                        {/* Bullet */}
                        <div className={`absolute left-0 top-1 w-7 h-7 rounded-full flex items-center justify-center border-2 z-10 transition-all ${
                          isCompleted ? 'bg-emerald-500 border-emerald-500 text-white' : 
                          isActive ? 'bg-indigo-600 border-indigo-600 text-white animate-pulse' : 
                          'bg-slate-900 border-slate-800 text-slate-600'
                        }`}>
                          {isCompleted ? <CheckCircle size={14} /> : isActive ? <Loader2 size={14} className="animate-spin" /> : <span className="text-[10px] font-bold">{i + 1}</span>}
                        </div>

                        <div className={`p-3 rounded-xl border transition-all ${
                          isActive ? 'bg-indigo-500/10 border-indigo-500/30 ring-1 ring-indigo-500/20' : 
                          isCompleted ? 'bg-slate-900/40 border-slate-800/40' : 
                          'bg-slate-900/20 border-slate-800/20'
                        }`}>
                          <p className="text-[11px] font-medium text-slate-400 leading-relaxed">
                            {step.thought}
                          </p>
                          <div className="mt-2 flex items-center gap-2 text-[10px] font-mono text-slate-500 bg-black/20 p-1.5 rounded-md border border-white/5">
                             <Play size={10} className={isActive ? 'text-indigo-400' : 'text-slate-600'} />
                             <span className="uppercase tracking-tighter truncate">{step.action.type}: {step.action.description}</span>
                          </div>

                          {step.requiresConfirmation && isActive && (
                            <div className="mt-3 flex gap-2">
                              <button onClick={onApproveAction} className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white text-[11px] py-2 rounded-lg font-bold transition-all transform active:scale-95 shadow-lg shadow-indigo-600/20">
                                PROCEED
                              </button>
                              <button onClick={onCancelAction} className="px-4 bg-slate-800 hover:bg-slate-700 text-slate-400 text-[11px] py-2 rounded-lg font-bold transition-colors">
                                HALT
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        ))}

        {status === AgentStatus.THINKING && (
          <div className="flex gap-4 animate-in fade-in duration-500">
            <div className="w-9 h-9 rounded-xl bg-indigo-600 flex items-center justify-center shrink-0">
              <Bot size={18} className="text-white" />
            </div>
            <div className="bg-slate-900/50 border border-slate-800/50 p-4 rounded-2xl rounded-tl-none flex items-center gap-4">
              <div className="flex gap-1.5">
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
              </div>
              <span className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">Routing Multi-Step Request...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-5 bg-slate-900/40 border-t border-slate-800/60 backdrop-blur-md">
        <form onSubmit={handleSubmit} className="relative">
          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            disabled={status !== AgentStatus.IDLE}
            onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(e); } }}
            placeholder={status === AgentStatus.IDLE ? "Command Nexus for autonomous workflows..." : "Execution in progress..."}
            className="w-full bg-slate-950/80 border border-slate-800 rounded-2xl px-5 py-4 pr-14 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600/30 transition-all resize-none min-h-[90px] text-slate-100 placeholder:text-slate-600 shadow-inner"
          />
          <button
            type="submit"
            disabled={status !== AgentStatus.IDLE || !inputValue.trim()}
            className="absolute bottom-4 right-4 p-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-20 disabled:cursor-not-allowed transition-all shadow-xl active:scale-90"
          >
            <Send size={20} />
          </button>
        </form>
        <div className="mt-4 flex items-center justify-between px-1">
           <div className="flex items-center gap-3">
              <div className="flex gap-1">
                {[...Array(3)].map((_, i) => <div key={i} className="w-1 h-1 rounded-full bg-slate-700"></div>)}
              </div>
              <span className="text-[10px] text-slate-500 font-bold uppercase tracking-tight">Nexus Kernel v1.2</span>
           </div>
           <div className="flex items-center gap-1">
             <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
             <span className="text-[10px] text-emerald-500/80 font-bold uppercase">Ready for Input</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default AgentControl;

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import VirtualLaptop from './components/VirtualLaptop';
import AgentControl from './components/AgentControl';
import { AgentStatus, Message, AgentAction, AgentStep, BrowserPage } from './types';
import { processUserIntent, generateMockPage } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'system',
      content: 'Nexus Autonomous Agent is active. Type a multi-step objective like "Research the current weather in Tokyo and then find a local cafe" to see me work.',
      timestamp: Date.now()
    }
  ]);
  const [status, setStatus] = useState<AgentStatus>(AgentStatus.IDLE);
  const [currentAction, setCurrentAction] = useState<AgentAction | null>(null);
  const [currentStepId, setCurrentStepId] = useState<string | undefined>();
  const [browserPage, setBrowserPage] = useState<BrowserPage | null>(null);

  useEffect(() => {
    handleManualNavigate('https://google.com');
  }, []);

  const handleManualNavigate = async (url: string) => {
    try {
      const page = await generateMockPage(url);
      setBrowserPage(page);
    } catch (e) {
      console.error("Navigation failed", e);
    }
  };

  const executeStep = async (step: AgentStep) => {
    setCurrentAction({ ...step.action, status: 'active' });
    setCurrentStepId(step.id);
    setStatus(AgentStatus.EXECUTING);

    // Simulate different action timings
    const duration = step.action.type.startsWith('BROWSER') ? 2000 : 1500;

    if (step.action.type === 'BROWSER_NAVIGATE') {
      const page = await generateMockPage(step.action.payload);
      setBrowserPage(page);
    }

    await new Promise(resolve => setTimeout(resolve, duration));

    // Update step status in message history
    setMessages(prev => prev.map(m => ({
      ...m,
      steps: m.steps?.map(s => s.id === step.id ? { ...s, action: { ...s.action, status: 'success' as const } } : s)
    })));

    setCurrentAction(null);
    return true;
  };

  const executeWorkflow = async (steps: AgentStep[]) => {
    for (const step of steps) {
      if (step.requiresConfirmation) {
        setStatus(AgentStatus.WAITING_FOR_USER);
        setCurrentStepId(step.id);
        return; // Pause execution for user input
      }
      await executeStep(step);
    }
    setStatus(AgentStatus.IDLE);
    setCurrentStepId(undefined);
  };

  const handleSendMessage = async (content: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setStatus(AgentStatus.THINKING);

    try {
      const result = await processUserIntent(content, messages);

      const workflowSteps: AgentStep[] = (result.steps || []).map((s: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        thought: s.thought,
        action: {
          id: Math.random().toString(36).substr(2, 9),
          ...s.action,
          status: 'pending',
          timestamp: Date.now()
        },
        requiresConfirmation: s.action.requiresConfirmation
      }));

      const agentMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'agent',
        content: result.content || (result.intent === 'WORKFLOW' ? `Executing multi-step objective: ${content}` : "I'm on it."),
        isThinking: !!result.isThinking,
        isAutonomous: result.intent === 'WORKFLOW',
        groundingSources: result.sources || [],
        steps: workflowSteps,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, agentMsg]);

      if (result.intent === 'WORKFLOW' && workflowSteps.length > 0) {
        setStatus(AgentStatus.PLANNING);
        await new Promise(resolve => setTimeout(resolve, 1000));
        await executeWorkflow(workflowSteps);
      } else {
        setStatus(AgentStatus.IDLE);
      }
    } catch (error) {
      console.error(error);
      setStatus(AgentStatus.IDLE);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: 'Autonomous Kernel Error: Failed to sequence task list.',
        timestamp: Date.now()
      }]);
    }
  };

  const handleApproveAction = async () => {
    const lastMsg = [...messages].reverse().find(m => m.steps && m.steps.length > 0);
    if (!lastMsg || !lastMsg.steps) return;

    const pendingSteps = lastMsg.steps.filter(s => s.action.status === 'pending');
    if (pendingSteps.length > 0) {
      await executeWorkflow(pendingSteps);
    }
  };

  const handleCancelAction = () => {
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);
    setCurrentStepId(undefined);
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'system',
      content: 'Autonomous workflow suspended by operator.',
      timestamp: Date.now()
    }]);
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden select-none">
      <Sidebar />
      <main className="flex-1 flex flex-col min-w-0">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/40 backdrop-blur-xl sticky top-0 z-50">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <div className="w-2.5 h-2.5 rounded-full bg-indigo-500 shadow-[0_0_12px_rgba(99,102,241,0.8)] animate-pulse"></div>
              <h1 className="text-sm font-bold text-slate-200 tracking-tight">NEXUS_ENV_AUTO_V1</h1>
            </div>
            <div className="h-4 w-px bg-slate-800"></div>
            <div className="flex gap-2">
              <span className="text-[10px] bg-emerald-500/10 text-emerald-500 px-2 py-0.5 rounded border border-emerald-500/20 font-bold uppercase tracking-wider">Autonomous Active</span>
            </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="text-right">
              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest leading-none mb-1">Compute Load</p>
              <div className="w-24 h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-indigo-500 transition-all duration-1000 ${status !== AgentStatus.IDLE ? 'w-3/4' : 'w-1/4'}`}></div>
              </div>
            </div>
            <button 
              onClick={() => window.location.reload()}
              className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 text-[11px] font-bold rounded-lg transition-all border border-slate-700 active:scale-95">
              Reset Session
            </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
          <VirtualLaptop 
            currentAction={currentAction} 
            pageContent={browserPage}
            onManualNavigate={handleManualNavigate}
          />
          <AgentControl 
            messages={messages} 
            status={status}
            currentStepId={currentStepId}
            onSendMessage={handleSendMessage}
            onApproveAction={handleApproveAction}
            onCancelAction={handleCancelAction}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

export enum AgentStatus {
  IDLE = 'idle',
  THINKING = 'thinking',
  PLANNING = 'planning',
  EXECUTING = 'executing',
  WAITING_FOR_USER = 'waiting',
  COMPLETED = 'completed',
  ERROR = 'error'
}

export type ActionType = 
  | 'BROWSER_NAVIGATE' 
  | 'BROWSER_CLICK' 
  | 'BROWSER_TYPE' 
  | 'TERMINAL_COMMAND' 
  | 'FILE_EDIT' 
  | 'SLACK_MESSAGE' 
  | 'GITHUB_PR' 
  | 'ZAPIER_TRIGGER'
  | 'SCRAPE_CONTENT'
  | 'SUMMARIZE_PAGE';

export interface GroundingChunk {
  web?: {
    uri: string;
    title: string;
  };
}

export interface BrowserElement {
  type: 'text' | 'button' | 'input' | 'heading' | 'link' | 'image';
  content?: string;
  label?: string;
  placeholder?: string;
}

export interface BrowserPage {
  url: string;
  title: string;
  elements: BrowserElement[];
}

export interface AgentAction {
  id: string;
  type: ActionType;
  description: string;
  payload: any;
  status: 'pending' | 'active' | 'success' | 'failed';
  timestamp: number;
}

export interface AgentStep {
  id: string;
  thought: string;
  action: AgentAction;
  requiresConfirmation?: boolean;
}

export interface Message {
  id: string;
  role: 'user' | 'agent' | 'system';
  content: string;
  timestamp: number;
  steps?: AgentStep[];
  isThinking?: boolean;
  isAutonomous?: boolean;
  isError?: boolean;
  groundingSources?: GroundingChunk[];
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AgentStep, GroundingChunk, BrowserPage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const AGENT_SYSTEM_PROMPT = `
You are Nexus, a high-performance Autonomous AI Agent.
Your goal is to execute complex, multi-step workflows.

When a user gives a command:
1. Break it down into a logical sequence of steps (WORKFLOW).
2. For each step, provide a 'thought' (reasoning) and an 'action'.
3. If the request is just a question, respond with CHAT intent.

Supported Action Types:
- BROWSER_NAVIGATE: payload is URL
- BROWSER_CLICK: payload is element description
- BROWSER_TYPE: payload is string to type
- TERMINAL_COMMAND: payload is bash command
- SCRAPE_CONTENT: payload is target data description

JSON RESPONSE FORMAT IS STRICT.
`;

const actionSchema = {
  type: Type.OBJECT,
  properties: {
    intent: { type: Type.STRING, description: "CHAT or WORKFLOW" },
    content: { type: Type.STRING, description: "Direct response for CHAT intent" },
    steps: {
      type: Type.ARRAY,
      description: "Sequence of actions for WORKFLOW intent",
      items: {
        type: Type.OBJECT,
        properties: {
          thought: { type: Type.STRING },
          action: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              description: { type: Type.STRING },
              payload: { type: Type.STRING },
              requiresConfirmation: { type: Type.BOOLEAN }
            },
            required: ["type", "description", "payload"]
          }
        },
        required: ["thought", "action"]
      }
    }
  },
  required: ["intent"]
};

export const generateMockPage = async (url: string): Promise<BrowserPage> => {
  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      elements: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING, description: "one of: text, button, input, heading, link, image" },
            content: { type: Type.STRING },
            label: { type: Type.STRING },
            placeholder: { type: Type.STRING }
          },
          required: ["type"]
        }
      }
    },
    required: ["title", "elements"]
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a simulated JSON layout for the website: ${url}. 
      Make it feel like a real page with a heading, some text, a few buttons, and maybe an input field.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema
      }
    });

    const data = JSON.parse(response.text || "{}");
    return {
      url,
      title: data.title || "Nexus Browser",
      elements: data.elements || []
    };
  } catch (e: any) {
    console.error("Simulation generation error:", e);
    return {
      url,
      title: "Error Loading Page",
      elements: [{ type: 'heading', content: 'Connection Error' }, { type: 'text', content: `The virtual browser failed to render this node: ${e.message || 'Unknown Error'}` }]
    };
  }
};

export const processUserIntent = async (prompt: string, history: any[]): Promise<any> => {
  try {
    const classifier = await ai.models.generateContent({
      model: 'gemini-2.5-flash-lite-latest',
      contents: `Classify request: "${prompt}". 
      Categories: SEARCH, COMPLEX, WORKFLOW, CHAT.
      Return ONLY category name.`,
    });

    const category = classifier.text.trim().toUpperCase();

    if (category.includes("SEARCH")) {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] }
      });
      return { intent: 'CHAT', content: response.text, sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] };
    }

    if (category.includes("COMPLEX")) {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [
          ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.content }] })),
          { role: 'user', parts: [{ text: prompt }] }
        ],
        config: { thinkingConfig: { thinkingBudget: 16000 } }
      });
      return { intent: 'CHAT', content: response.text, isThinking: true };
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ role: 'user', parts: [{ text: `Task: ${prompt}` }] }],
      config: {
        systemInstruction: AGENT_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: actionSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error: any) {
    console.error("Intent processing error:", error);
    if (error.message?.includes("API_KEY")) throw new Error("API configuration error. Please ensure environment variables are correctly mapped.");
    if (error.message?.includes("safety")) throw new Error("This request triggered a safety filter and cannot be processed.");
    if (error.message?.includes("quota")) throw new Error("API quota exceeded. Please try again later.");
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, CheckCircle, AlertCircle, Loader2, User, Bot, Play, Pause, ExternalLink, BrainCircuit, Globe, ChevronDown, ListTodo, Activity, RefreshCcw } from 'lucide-react';
import { Message, AgentStatus, AgentStep } from '../types';

interface AgentControlProps {
  messages: Message[];
  status: AgentStatus;
  currentStepId?: string;
  onSendMessage: (content: string) => void;
  onApproveAction: () => void;
  onCancelAction: () => void;
}

const AgentControl: React.FC<AgentControlProps> = ({ 
  messages, 
  status, 
  currentStepId,
  onSendMessage, 
  onApproveAction, 
  onCancelAction 
}) => {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, status]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputValue.trim() && status === AgentStatus.IDLE) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  const calculateProgress = (steps: AgentStep[]) => {
    if (!steps || steps.length === 0) return 0;
    const completed = steps.filter(s => s.action.status === 'success').length;
    return Math.round((completed / steps.length) * 100);
  };

  return (
    <div className="w-[420px] border-l border-slate-800 flex flex-col h-full bg-slate-950/80 backdrop-blur-xl">
      <div className="p-5 border-b border-slate-800/60 bg-slate-900/40 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="relative">
            <div className={`w-3.5 h-3.5 rounded-full ${
              status === AgentStatus.EXECUTING ? 'bg-emerald-500 shadow-[0_0_12px_rgba(16,185,129,0.5)]' :
              status === AgentStatus.THINKING || status === AgentStatus.PLANNING ? 'bg-indigo-500 shadow-[0_0_12px_rgba(99,102,241,0.5)]' :
              status === AgentStatus.WAITING_FOR_USER ? 'bg-amber-500' : 
              status === AgentStatus.ERROR ? 'bg-red-500 shadow-[0_0_12px_rgba(239,68,68,0.5)]' :
              'bg-slate-600'
            }`}></div>
            {(status === AgentStatus.EXECUTING || status === AgentStatus.THINKING) && (
               <div className="absolute -inset-1 rounded-full border border-current animate-ping opacity-20"></div>
            )}
          </div>
          <div>
            <h2 className="font-bold text-sm text-slate-200">Nexus Autonomous Node</h2>
            <div className="flex items-center gap-1.5">
               <span className={`text-[10px] uppercase font-bold tracking-widest ${status === AgentStatus.ERROR ? 'text-red-400' : 'text-slate-500'}`}>
                {status}
               </span>
               {status === AgentStatus.EXECUTING && <Activity size={10} className="text-emerald-500 animate-pulse" />}
               {status === AgentStatus.ERROR && <AlertCircle size={10} className="text-red-500" />}
            </div>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-8 scroll-smooth custom-scrollbar">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
            <div className={`w-9 h-9 rounded-xl flex items-center justify-center shrink-0 shadow-lg ${
              msg.role === 'user' ? 'bg-slate-800 border border-slate-700' : 
              msg.role === 'system' && msg.isError ? 'bg-red-950 border border-red-500/50 text-red-500' :
              'bg-gradient-to-br from-indigo-500 to-indigo-700 text-white'
            }`}>
              {msg.role === 'user' ? <User size={18} /> : 
               msg.role === 'system' && msg.isError ? <AlertCircle size={18} /> : 
               <Bot size={18} />}
            </div>

            <div className={`flex-1 max-w-[88%] ${msg.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl text-[13px] leading-relaxed relative ${
                msg.role === 'user' 
                  ? 'bg-indigo-600/10 border border-indigo-500/20 text-slate-100 rounded-tr-none' 
                  : msg.role === 'system' && msg.isError 
                  ? 'bg-red-500/10 border border-red-500/30 text-red-200 rounded-tl-none shadow-xl'
                  : 'bg-slate-900/60 border border-slate-800/50 text-slate-200 rounded-tl-none shadow-2xl backdrop-blur-md'
              }`}>
                {msg.isThinking && (
                  <div className="flex items-center gap-2 mb-3 p-2 bg-indigo-500/10 rounded-lg border border-indigo-500/20 text-[10px] text-indigo-400 font-bold uppercase tracking-wider">
                    <BrainCircuit size={14} className="animate-pulse" />
                    Deep Reasoning Path Active
                  </div>
                )}

                {msg.role === 'system' && msg.isError && (
                  <div className="flex items-center gap-2 mb-2 text-[10px] text-red-400 font-bold uppercase tracking-widest">
                    Kernel Interrupt Detected
                  </div>
                )}

                <div className="whitespace-pre-wrap">{msg.content}</div>

                {msg.groundingSources && msg.groundingSources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-800 space-y-2">
                    <div className="flex items-center gap-1.5 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                      <Globe size={10} /> Grounding Sources
                    </div>
                    {msg.groundingSources.map((source, idx) => (
                      source.web && (
                        <a key={idx} href={source.web.uri} target="_blank" rel="noopener noreferrer" 
                           className="flex items-center justify-between p-2.5 rounded-lg bg-slate-950/50 hover:bg-slate-800/80 transition-all border border-slate-800 group">
                          <span className="text-[11px] text-indigo-400 truncate max-w-[240px] font-medium">{source.web.title || source.web.uri}</span>
                          <ExternalLink size={12} className="text-slate-600 group-hover:text-indigo-400" />
                        </a>
                      )
                    ))}
                  </div>
                )}

                {msg.role === 'system' && msg.isError && (
                  <button 
                    onClick={() => window.location.reload()}
                    className="mt-4 w-full flex items-center justify-center gap-2 p-2 bg-red-500 hover:bg-red-600 text-white rounded-lg text-xs font-bold transition-all"
                  >
                    <RefreshCcw size={14} /> Reinitialize Kernel
                  </button>
                )}
              </div>

              {msg.steps && msg.steps.length > 0 && (
                <div className="mt-4 space-y-3 relative">
                  <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                      <ListTodo size={12} /> Workflow Execution Plan
                    </div>
                    <div className="text-[10px] font-bold text-indigo-400 bg-indigo-500/10 px-2 py-0.5 rounded border border-indigo-500/20">
                      {calculateProgress(msg.steps)}% COMPLETED
                    </div>
                  </div>

                  <div className="absolute left-[13px] top-10 bottom-4 w-0.5 bg-slate-800 rounded-full"></div>

                  {msg.steps.map((step, i) => {
                    const isActive = step.id === currentStepId;
                    const isCompleted = step.action.status === 'success';
                    const isFailed = step.action.status === 'failed';

                    return (
                      <div key={step.id} className={`relative pl-8 transition-all duration-300 ${isActive ? 'opacity-100' : (isCompleted || isFailed) ? 'opacity-70' : 'opacity-40'}`}>
                        <div className={`absolute left-0 top-1 w-7 h-7 rounded-full flex items-center justify-center border-2 z-10 transition-all ${
                          isCompleted ? 'bg-emerald-500 border-emerald-500 text-white' : 
                          isFailed ? 'bg-red-500 border-red-500 text-white' :
                          isActive ? 'bg-indigo-600 border-indigo-600 text-white animate-pulse' : 
                          'bg-slate-900 border-slate-800 text-slate-600'
                        }`}>
                          {isCompleted ? <CheckCircle size={14} /> : 
                           isFailed ? <AlertCircle size={14} /> :
                           isActive ? <Loader2 size={14} className="animate-spin" /> : 
                           <span className="text-[10px] font-bold">{i + 1}</span>}
                        </div>

                        <div className={`p-3 rounded-xl border transition-all ${
                          isActive ? 'bg-indigo-500/10 border-indigo-500/30 ring-1 ring-indigo-500/20' : 
                          isFailed ? 'bg-red-500/5 border-red-500/30' :
                          isCompleted ? 'bg-slate-900/40 border-slate-800/40' : 
                          'bg-slate-900/20 border-slate-800/20'
                        }`}>
                          <p className={`text-[11px] font-medium leading-relaxed ${isFailed ? 'text-red-300' : 'text-slate-400'}`}>
                            {step.thought}
                          </p>
                          <div className={`mt-2 flex items-center gap-2 text-[10px] font-mono p-1.5 rounded-md border border-white/5 ${isFailed ? 'bg-red-950/40 text-red-400' : 'bg-black/20 text-slate-500'}`}>
                             <Play size={10} className={isActive ? 'text-indigo-400' : isFailed ? 'text-red-400' : 'text-slate-600'} />
                             <span className="uppercase tracking-tighter truncate">{step.action.type}: {step.action.description}</span>
                          </div>

                          {step.requiresConfirmation && isActive && (
                            <div className="mt-3 flex gap-2">
                              <button onClick={onApproveAction} className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white text-[11px] py-2 rounded-lg font-bold transition-all transform active:scale-95 shadow-lg shadow-indigo-600/20">
                                PROCEED
                              </button>
                              <button onClick={onCancelAction} className="px-4 bg-slate-800 hover:bg-slate-700 text-slate-400 text-[11px] py-2 rounded-lg font-bold transition-colors">
                                HALT
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        ))}

        {status === AgentStatus.THINKING && (
          <div className="flex gap-4 animate-in fade-in duration-500">
            <div className="w-9 h-9 rounded-xl bg-indigo-600 flex items-center justify-center shrink-0">
              <Bot size={18} className="text-white" />
            </div>
            <div className="bg-slate-900/50 border border-slate-800/50 p-4 rounded-2xl rounded-tl-none flex items-center gap-4">
              <div className="flex gap-1.5">
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
              </div>
              <span className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">Routing Multi-Step Request...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-5 bg-slate-900/40 border-t border-slate-800/60 backdrop-blur-md">
        <form onSubmit={handleSubmit} className="relative">
          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            disabled={status !== AgentStatus.IDLE && status !== AgentStatus.ERROR}
            onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(e); } }}
            placeholder={status === AgentStatus.IDLE || status === AgentStatus.ERROR ? "Command Nexus for autonomous workflows..." : "Execution in progress..."}
            className={`w-full bg-slate-950/80 border rounded-2xl px-5 py-4 pr-14 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600/30 transition-all resize-none min-h-[90px] text-slate-100 placeholder:text-slate-600 shadow-inner ${status === AgentStatus.ERROR ? 'border-red-500/40' : 'border-slate-800'}`}
          />
          <button
            type="submit"
            disabled={(status !== AgentStatus.IDLE && status !== AgentStatus.ERROR) || !inputValue.trim()}
            className={`absolute bottom-4 right-4 p-2.5 rounded-xl transition-all shadow-xl active:scale-90 ${status === AgentStatus.ERROR ? 'bg-red-600 hover:bg-red-700 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-20 disabled:cursor-not-allowed'}`}
          >
            <Send size={20} />
          </button>
        </form>
        <div className="mt-4 flex items-center justify-between px-1">
           <div className="flex items-center gap-3">
              <div className="flex gap-1">
                {[...Array(3)].map((_, i) => <div key={i} className={`w-1 h-1 rounded-full ${status === AgentStatus.ERROR ? 'bg-red-500' : 'bg-slate-700'}`}></div>)}
              </div>
              <span className="text-[10px] text-slate-500 font-bold uppercase tracking-tight">Nexus Kernel v1.2</span>
           </div>
           <div className="flex items-center gap-1">
             <div className={`w-1.5 h-1.5 rounded-full ${status === AgentStatus.ERROR ? 'bg-red-500' : 'bg-emerald-500'}`}></div>
             <span className={`text-[10px] font-bold uppercase ${status === AgentStatus.ERROR ? 'text-red-500' : 'text-emerald-500/80'}`}>
              {status === AgentStatus.ERROR ? 'Interrupt Status' : 'Ready for Input'}
             </span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default AgentControl;

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import VirtualLaptop from './components/VirtualLaptop';
import AgentControl from './components/AgentControl';
import { AgentStatus, Message, AgentAction, AgentStep, BrowserPage } from './types';
import { processUserIntent, generateMockPage } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'system',
      content: 'Nexus Autonomous Agent is active. Type a multi-step objective like "Research the current weather in Tokyo and then find a local cafe" to see me work.',
      timestamp: Date.now()
    }
  ]);
  const [status, setStatus] = useState<AgentStatus>(AgentStatus.IDLE);
  const [currentAction, setCurrentAction] = useState<AgentAction | null>(null);
  const [currentStepId, setCurrentStepId] = useState<string | undefined>();
  const [browserPage, setBrowserPage] = useState<BrowserPage | null>(null);

  useEffect(() => {
    handleManualNavigate('https://google.com');
  }, []);

  const handleManualNavigate = async (url: string) => {
    try {
      const page = await generateMockPage(url);
      setBrowserPage(page);
    } catch (e) {
      console.error("Navigation failed", e);
    }
  };

  const executeStep = async (step: AgentStep) => {
    setCurrentAction({ ...step.action, status: 'active' });
    setCurrentStepId(step.id);
    setStatus(AgentStatus.EXECUTING);

    try {
      // Simulate different action timings
      const duration = step.action.type.startsWith('BROWSER') ? 2000 : 1500;

      if (step.action.type === 'BROWSER_NAVIGATE') {
        const page = await generateMockPage(step.action.payload);
        if (page.title === "Error Loading Page") throw new Error("Simulation site unreachable.");
        setBrowserPage(page);
      }

      await new Promise(resolve => setTimeout(resolve, duration));

      // Update step status in message history to success
      setMessages(prev => prev.map(m => ({
        ...m,
        steps: m.steps?.map(s => s.id === step.id ? { ...s, action: { ...s.action, status: 'success' as const } } : s)
      })));

      setCurrentAction(null);
      return true;
    } catch (error: any) {
      console.error("Step execution failed:", error);
      setMessages(prev => prev.map(m => ({
        ...m,
        steps: m.steps?.map(s => s.id === step.id ? { ...s, action: { ...s.action, status: 'failed' as const } } : s)
      })));
      setCurrentAction(null);
      throw error;
    }
  };

  const executeWorkflow = async (steps: AgentStep[]) => {
    try {
      for (const step of steps) {
        if (step.requiresConfirmation) {
          setStatus(AgentStatus.WAITING_FOR_USER);
          setCurrentStepId(step.id);
          return; // Pause execution for user input
        }
        await executeStep(step);
      }
      setStatus(AgentStatus.IDLE);
      setCurrentStepId(undefined);
    } catch (error: any) {
      setStatus(AgentStatus.ERROR);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: `Workflow execution halted: ${error.message || 'Unknown internal error.'}`,
        timestamp: Date.now(),
        isError: true
      }]);
    }
  };

  const handleSendMessage = async (content: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setStatus(AgentStatus.THINKING);

    try {
      const result = await processUserIntent(content, messages);

      const workflowSteps: AgentStep[] = (result.steps || []).map((s: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        thought: s.thought,
        action: {
          id: Math.random().toString(36).substr(2, 9),
          ...s.action,
          status: 'pending',
          timestamp: Date.now()
        },
        requiresConfirmation: s.action.requiresConfirmation
      }));

      const agentMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'agent',
        content: result.content || (result.intent === 'WORKFLOW' ? `Objective acknowledged. Planning multi-step strategy...` : "I'm on it."),
        isThinking: !!result.isThinking,
        isAutonomous: result.intent === 'WORKFLOW',
        groundingSources: result.sources || [],
        steps: workflowSteps,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, agentMsg]);

      if (result.intent === 'WORKFLOW' && workflowSteps.length > 0) {
        setStatus(AgentStatus.PLANNING);
        await new Promise(resolve => setTimeout(resolve, 1000));
        await executeWorkflow(workflowSteps);
      } else {
        setStatus(AgentStatus.IDLE);
      }
    } catch (error: any) {
      console.error(error);
      setStatus(AgentStatus.ERROR);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: error.message || 'Autonomous Kernel Error: Failed to sequence task list.',
        timestamp: Date.now(),
        isError: true
      }]);
    }
  };

  const handleApproveAction = async () => {
    const lastMsg = [...messages].reverse().find(m => m.steps && m.steps.length > 0);
    if (!lastMsg || !lastMsg.steps) return;

    const pendingSteps = lastMsg.steps.filter(s => s.action.status === 'pending');
    if (pendingSteps.length > 0) {
      await executeWorkflow(pendingSteps);
    }
  };

  const handleCancelAction = () => {
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);
    setCurrentStepId(undefined);
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'system',
      content: 'Autonomous workflow suspended by operator.',
      timestamp: Date.now()
    }]);
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden select-none">
      <Sidebar />
      <main className="flex-1 flex flex-col min-w-0">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/40 backdrop-blur-xl sticky top-0 z-50">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <div className={`w-2.5 h-2.5 rounded-full shadow-[0_0_12px_rgba(99,102,241,0.8)] animate-pulse ${status === AgentStatus.ERROR ? 'bg-red-500' : 'bg-indigo-500'}`}></div>
              <h1 className="text-sm font-bold text-slate-200 tracking-tight">NEXUS_ENV_AUTO_V1</h1>
            </div>
            <div className="h-4 w-px bg-slate-800"></div>
            <div className="flex gap-2">
              <span className={`text-[10px] px-2 py-0.5 rounded border font-bold uppercase tracking-wider ${status === AgentStatus.ERROR ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'}`}>
                {status === AgentStatus.ERROR ? 'Interrupt Active' : 'Autonomous Active'}
              </span>
            </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="text-right">
              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest leading-none mb-1">Compute Load</p>
              <div className="w-24 h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full transition-all duration-1000 ${status === AgentStatus.ERROR ? 'bg-red-500 w-full' : status !== AgentStatus.IDLE ? 'bg-indigo-50 w-3/4' : 'bg-indigo-500 w-1/4'}`}></div>
              </div>
            </div>
            <button 
              onClick={() => window.location.reload()}
              className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 text-[11px] font-bold rounded-lg transition-all border border-slate-700 active:scale-95">
              Reset Session
            </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
          <VirtualLaptop 
            currentAction={currentAction} 
            pageContent={browserPage}
            onManualNavigate={handleManualNavigate}
          />
          <AgentControl 
            messages={messages} 
            status={status}
            currentStepId={currentStepId}
            onSendMessage={handleSendMessage}
            onApproveAction={handleApproveAction}
            onCancelAction={handleCancelAction}
          />
        </div>
      </main>
    </div>
  );
};

