export enum AgentStatus {
  IDLE = 'idle',
  THINKING = 'thinking',
  PLANNING = 'planning',
  EXECUTING = 'executing',
  WAITING_FOR_USER = 'waiting',
  COMPLETED = 'completed',
  ERROR = 'error'
}

export type ActionType = 
  | 'BROWSER_NAVIGATE' 
  | 'BROWSER_CLICK' 
  | 'BROWSER_TYPE' 
  | 'TERMINAL_COMMAND' 
  | 'FILE_NAVIGATE'
  | 'FILE_READ'
  | 'FILE_WRITE'
  | 'FILE_EDIT' 
  | 'SLACK_MESSAGE' 
  | 'GITHUB_PR' 
  | 'ZAPIER_TRIGGER'
  | 'SCRAPE_CONTENT'
  | 'SUMMARIZE_PAGE';

