const VirtualLaptop: React.FC<VirtualLaptopProps> = ({ activeView, currentAction, pageContent, onManualNavigate, onViewChange }) => {
  const [urlInput, setUrlInput] = useState('https://github.com/trending');
  const [terminalLines, setTerminalLines] = useState<string[]>(['Nexus OS v1.0.4', 'Checking connectivity...', 'All systems green.', 'Type "help" for a list of commands.']);
  const [terminalInput, setTerminalInput] = useState('');
  const [commandHistory, setCommandHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [terminalFocused, setTerminalFocused] = useState(false);

  const [browserLoading, setBrowserLoading] = useState(false);
  const [cursorPos, setCursorPos] = useState({ x: 50, y: 50 });
  const [ripples, setRipples] = useState<{id: number, x: number, y: number}[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const [typedText, setTypedText] = useState('');
  const [activeTarget, setActiveTarget] = useState<{x: number, y: number} | null>(null);

  // Filesystem State
  const [currentPath, setCurrentPath] = useState<string[]>([]);
  const [fsSelection, setFsSelection] = useState<string | null>(null);

  const browserRef = useRef<HTMLDivElement>(null);
  const terminalScrollRef = useRef<HTMLDivElement>(null);
  const terminalInputRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (pageContent) {
      setUrlInput(pageContent.url);
      setBrowserLoading(false);
    }
  }, [pageContent]);

  useEffect(() => {
    if (terminalScrollRef.current) {
      terminalScrollRef.current.scrollTop = terminalScrollRef.current.scrollHeight;
    }
  }, [terminalLines, terminalInput, currentAction]);

  useEffect(() => {
    if (!currentAction) {
      setIsTyping(false);
      setActiveTarget(null);
      return;
    }

    if (currentAction.type === 'BROWSER_NAVIGATE') {
      onViewChange('browser');
      setBrowserLoading(true);
      setUrlInput(currentAction.payload);
    }

    if (currentAction.type === 'FILE_NAVIGATE') {
      onViewChange('filesystem');
      const pathStr = currentAction.payload as string;
      const parts = pathStr.split('/').filter(p => p);
      setCurrentPath(parts);
    }

    if (currentAction.type === 'BROWSER_CLICK') {
      const targetX = 20 + Math.random() * 60;
      const targetY = 30 + Math.random() * 50;
      setCursorPos({ x: targetX, y: targetY });
      setActiveTarget({ x: targetX, y: targetY });
      const clickTimer = setTimeout(() => {
        setRipples(prev => [...prev, { id: Date.now(), x: targetX, y: targetY }]);
        setTimeout(() => setRipples(prev => prev.slice(1)), 800);
      }, 800);
      return () => clearTimeout(clickTimer);
    }

    if (currentAction.type === 'TERMINAL_COMMAND') {
      onViewChange('terminal');
      const timer = setTimeout(() => {
        setTerminalLines(prev => [
          ...prev, 
          `> ${currentAction.payload}`, 
          `[PROCESS] Executing sequence...`,
          `[OK] Task acknowledged.`
        ]);
      }, 1200);
      return () => clearTimeout(timer);
    }
  }, [currentAction]);

  const handleUrlSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setBrowserLoading(true);
    onManualNavigate(urlInput);
  };

  const executeTerminalCommand = (cmd: string) => {
    const trimmed = cmd.trim();
    if (!trimmed) return;

    setTerminalLines(prev => [...prev, `nexus@alpha:~$ ${trimmed}`]);

    if (trimmed === 'clear') {
      setTerminalLines([]);
    } else if (trimmed === 'help') {
      setTerminalLines(prev => [...prev, 'Available commands:', ...COMMON_COMMANDS.map(c => ` - ${c}`)]);
    } else if (trimmed === 'status') {
      setTerminalLines(prev => [...prev, 'Nexus Node: Online', 'Uptime: 14h 22m', 'Load: 0.12, 0.08, 0.05']);
    } else if (trimmed === 'system-info') {
      setTerminalLines(prev => [...prev, 'OS: Nexus Runtime v1.0.4', 'Kernel: NodeX 5.15.0', 'Memory: 16GB Virtualized']);
    } else if (trimmed.startsWith('cd ')) {
      const path = trimmed.substring(3).trim();
      if (path === '..') {
        setCurrentPath(prev => prev.slice(0, -1));
      } else {
        setCurrentPath(prev => [...prev, path]);
      }
      onViewChange('filesystem');
    } else {
      setTerminalLines(prev => [...prev, `sh: command not found: ${trimmed.split(' ')[0]}`]);
    }

    setCommandHistory(prev => [trimmed, ...prev.filter(c => c !== trimmed)].slice(0, 50));
    setHistoryIndex(-1);
    setTerminalInput('');
  };

  const handleTerminalKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      executeTerminalCommand(terminalInput);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      const nextIndex = historyIndex + 1;
      if (nextIndex < commandHistory.length) {
        setHistoryIndex(nextIndex);
        setTerminalInput(commandHistory[nextIndex]);
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      const nextIndex = historyIndex - 1;
      if (nextIndex >= 0) {
        setHistoryIndex(nextIndex);
        setTerminalInput(commandHistory[nextIndex]);
      } else {
        setHistoryIndex(-1);
        setTerminalInput('');
      }
    }
  };

  const getCurrentFolder = (): FileEntry[] => {
    let current = MOCK_FS;
    for (const part of currentPath) {
      const found = current.find(f => f.name === part && f.type === 'folder');
      if (found && found.children) {
        current = found.children;
      } else {
