        return <button key={idx} className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold text-sm hover:bg-indigo-700 transition-colors mr-3 mb-3 shadow-sm">{el.label}</button>;
      case 'input':
        return <input key={idx} type="text" placeholder={el.placeholder} className="w-full border border-slate-200 rounded-lg px-4 py-2 mb-4 bg-white shadow-inner focus:ring-2 focus:ring-indigo-500/20 outline-none" readOnly />;
      case 'link':
        return <a key={idx} href="#" className="text-indigo-600 underline font-medium mr-4 mb-3 inline-block">{el.label}</a>;
      default:
        return null;
    }
  };

  return (
    <div className="flex-1 p-6 h-full overflow-hidden flex flex-col gap-6">
      <div className="flex-1 bg-slate-900 rounded-xl border border-slate-700 shadow-2xl flex flex-col overflow-hidden relative group">

        {/* Navigation Bar */}
        <div className="bg-slate-800 p-2 flex items-center gap-3 border-b border-slate-700 z-30">
          <div className="flex gap-1.5 px-2">
            <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-amber-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
          </div>
          <div className="flex gap-2">
            <button onClick={() => activeView === 'filesystem' && setCurrentPath(prev => prev.slice(0, -1))} className="p-1 hover:bg-slate-700 rounded transition-colors">
              <ChevronLeft size={18} className="text-slate-500" />
            </button>
            <ChevronRight size={18} className="text-slate-500" />
            <RotateCcw size={18} className={`${browserLoading ? 'animate-spin text-indigo-400' : 'text-slate-500'}`} />
          </div>

          {activeView === 'browser' ? (
            <form onSubmit={handleUrlSubmit} className="flex-1 bg-slate-950/50 rounded-md border border-slate-700/50 px-3 py-1 flex items-center gap-2 relative overflow-hidden">
              <Search size={14} className="text-slate-500" />
              <input 
                value={urlInput}
                onChange={(e) => setUrlInput(e.target.value)}
                className="bg-transparent border-none outline-none text-xs text-slate-300 font-medium w-full"
              />
              {browserLoading && (
                <div className="absolute bottom-0 left-0 h-[2px] bg-indigo-500 w-full animate-pulse shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
              )}
            </form>
          ) : (
            <div className="flex-1 flex items-center gap-2 bg-slate-950/50 rounded-md border border-slate-700/50 px-3 py-1">
              <HardDrive size={14} className="text-indigo-400" />
              <div className="flex items-center text-xs font-medium text-slate-400">
                <span className="hover:text-indigo-400 cursor-pointer" onClick={() => setCurrentPath([])}>root</span>
                {currentPath.map((p, i) => (
                  <React.Fragment key={i}>
                    <ChevronRightSmall size={14} className="mx-1 text-slate-600" />
                    <span className="hover:text-indigo-400 cursor-pointer" onClick={() => setCurrentPath(currentPath.slice(0, i + 1))}>{p}</span>
                  </React.Fragment>
                ))}
              </div>
            </div>
          )}

          <div className="flex gap-2 px-2 items-center">
             <div className="hidden sm:flex items-center gap-1 bg-slate-700/50 px-2 py-0.5 rounded text-[10px] text-slate-400 font-bold border border-slate-600">
                {activeView.toUpperCase()} MODE
             </div>
            <Share2 size={16} className="text-slate-500" />
            <Plus size={16} className="text-slate-500" />
          </div>
        </div>

        {/* Workspace Content */}
        <div ref={browserRef} className={`flex-1 overflow-auto relative ${activeView === 'browser' ? 'bg-slate-50' : 'bg-slate-950'}`}>

          {currentAction && (
            <div className="absolute top-6 left-6 z-40 flex flex-col gap-2">
              <div className="bg-slate-900/90 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold shadow-xl border border-white/10 flex items-center gap-3 backdrop-blur-md">
                 <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></div>
                 <span className="uppercase tracking-widest text-slate-400">Active Task</span>
                 <span className="text-indigo-400">{currentAction.type}</span>
              </div>
            </div>
          )}

          {activeView === 'browser' ? (
            <div className={`p-10 max-w-4xl mx-auto space-y-4 transition-all duration-500 ${browserLoading ? 'opacity-20 scale-95 blur-sm' : 'opacity-100 scale-100'}`}>
              {pageContent ? (
                <div className="animate-in fade-in zoom-in-95 duration-500 text-slate-900">
                  <div className="border-b border-slate-200 pb-6 mb-8 flex items-center gap-3">
                     <div className="p-3 bg-indigo-600 rounded-lg text-white shadow-lg">
                        <Globe size={24} />
                     </div>
                     <div>
                        <h1 className="text-2xl font-black text-slate-900 leading-none">{pageContent.title}</h1>
                        <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">{pageContent.url}</p>
                     </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12">
                     <div>{pageContent.elements.slice(0, Math.ceil(pageContent.elements.length / 2)).map(renderElement)}</div>
                     <div>{pageContent.elements.slice(Math.ceil(pageContent.elements.length / 2)).map(renderElement)}</div>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-center">
                   <div className="w-20 h-20 bg-slate-200 rounded-3xl animate-pulse mb-6"></div>
                   <div className="h-6 w-48 bg-slate-200 rounded mb-4 animate-pulse"></div>
                   <div className="h-4 w-64 bg-slate-100 rounded animate-pulse"></div>
                </div>
              )}
            </div>
          ) : activeView === 'filesystem' ? (
            <div className="p-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-8">
                 <h2 className="text-xl font-bold text-white flex items-center gap-2">
                   <Folder className="text-indigo-400" />
                   Storage Explorer
                 </h2>
                 <div className="flex gap-2">
                   <button className="bg-slate-800 text-slate-300 text-xs px-3 py-1.5 rounded-lg border border-slate-700 hover:bg-slate-700 transition-colors">New Folder</button>
                   <button className="bg-indigo-600 text-white text-xs px-3 py-1.5 rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/20">Upload</button>
                 </div>
              </div>

              <div className="grid grid-cols-1 gap-1">
                 {/* Table Header */}
                 <div className="grid grid-cols-12 px-4 py-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest border-b border-slate-800/50">
                    <div className="col-span-6">Name</div>
                    <div className="col-span-2">Size</div>
                    <div className="col-span-3">Last Modified</div>
                    <div className="col-span-1 text-right">Action</div>
                 </div>

                 {getCurrentFolder().map((item, idx) => (
                   <div 
                    key={idx} 
                    onClick={() => {
                      if (item.type === 'folder') setCurrentPath([...currentPath, item.name]);
                      setFsSelection(item.name);
                    }}
                    className={`grid grid-cols-12 items-center px-4 py-3 rounded-xl border transition-all cursor-pointer group ${
                      fsSelection === item.name 
                        ? 'bg-indigo-500/10 border-indigo-500/30 ring-1 ring-indigo-500/20' 
                        : 'bg-transparent border-transparent hover:bg-slate-900/40 hover:border-slate-800'
                    }`}
                   >
                     <div className="col-span-6 flex items-center gap-3">
                        {item.type === 'folder' ? <Folder size={18} className="text-indigo-400 fill-indigo-400/10" /> : <FileText size={18} className="text-slate-400" />}
                        <span className="text-sm font-medium text-slate-200">{item.name}</span>
                     </div>
                     <div className="col-span-2 text-xs text-slate-500 font-mono">{item.size || '--'}</div>
                     <div className="col-span-3 flex items-center gap-2 text-xs text-slate-500">
                        <Clock size={12} />
                        {item.lastModified || '--'}
                     </div>
                     <div className="col-span-1 text-right">
                        <MoreVertical size={14} className="text-slate-700 group-hover:text-slate-400 inline" />
                     </div>
                   </div>
                 ))}

                 {getCurrentFolder().length === 0 && (
                   <div className="py-20 flex flex-col items-center justify-center opacity-40">
                      <Folder size={48} className="text-slate-700 mb-4" />
                      <p className="text-sm text-slate-500 font-medium italic">Directory is empty</p>
                   </div>
                 )}
              </div>
            </div>
          ) : (
             <div className="flex flex-col h-full bg-slate-950 font-mono">
                <div className="p-6 text-emerald-500 space-y-2 overflow-y-auto flex-1 custom-scrollbar">
                   {terminalLines.map((line, i) => (
                      <div key={i} className="flex gap-4">
                        <span className="text-slate-700">[{new Date().toLocaleTimeString()}]</span>
                        <span className={line.startsWith('>') ? 'text-indigo-400' : 'text-emerald-500'}>{line}</span>
                      </div>
                   ))}
                </div>
                <div className="p-4 border-t border-slate-800 bg-black/40 flex gap-4 items-center">
                   <span className="text-indigo-400 font-bold whitespace-nowrap">nexus@alpha:~$</span>
                   <input 
                    autoFocus
                    value={terminalInput}
                    onChange={(e) => setTerminalInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && executeTerminalCommand(terminalInput)}
                    className="flex-1 bg-transparent border-none outline-none text-white text-sm"
                    placeholder="Execute system call..."
                   />
                </div>
             </div>
          )}
        </div>
      </div>

      {/* Mini Terminal / Console Overlay if not in terminal view */}
      {activeView !== 'terminal' && (
        <div 
          className={`h-40 bg-slate-950 rounded-xl border transition-all duration-200 flex flex-col overflow-hidden font-mono text-sm relative border-slate-800 shadow-xl`}
          onClick={() => terminalInputRef.current?.focus()}
        >
          <div className="bg-slate-900/80 px-4 py-2 border-b border-slate-800 flex items-center justify-between z-20 backdrop-blur-md">
            <div className="flex items-center gap-2 text-slate-400">
              <TerminalIcon size={14} className="text-emerald-500" />
              <span className="text-[10px] font-bold uppercase tracking-wider">nexus-runtime console</span>
            </div>
          </div>
          <div ref={terminalScrollRef} className="flex-1 p-4 text-[11px] text-emerald-500/80 overflow-y-auto space-y-1 scroll-smooth custom-scrollbar">
            {terminalLines.slice(-10).map((line, i) => (
              <div key={i} className="flex gap-2">
                <span className="text-slate-700 font-bold opacity-50">&gt;</span>
                <span className="truncate">{line}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default VirtualLaptop;

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import VirtualLaptop from './components/VirtualLaptop';
import AgentControl from './components/AgentControl';
import { AgentStatus, Message, AgentAction, AgentStep, BrowserPage, ViewType } from './types';
import { processUserIntent, generateMockPage } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'system',
      content: 'Nexus Autonomous Agent is active. Type a multi-step objective like "Research the current weather in Tokyo and then find a local cafe" to see me work.',
      timestamp: Date.now()
    }
  ]);
  const [status, setStatus] = useState<AgentStatus>(AgentStatus.IDLE);
  const [currentAction, setCurrentAction] = useState<AgentAction | null>(null);
  const [currentStepId, setCurrentStepId] = useState<string | undefined>();
  const [browserPage, setBrowserPage] = useState<BrowserPage | null>(null);
  const [activeView, setActiveView] = useState<ViewType>('browser');

  useEffect(() => {
    handleManualNavigate('https://google.com');
  }, []);

  const handleManualNavigate = async (url: string) => {
    try {
      const page = await generateMockPage(url);
      setBrowserPage(page);
    } catch (e) {
      console.error("Navigation failed", e);
    }
  };

  const executeStep = async (step: AgentStep) => {
    setCurrentAction({ ...step.action, status: 'active' });
    setCurrentStepId(step.id);
    setStatus(AgentStatus.EXECUTING);

    try {
      const duration = step.action.type.startsWith('BROWSER') ? 2000 : 1500;

      if (step.action.type === 'BROWSER_NAVIGATE') {
        setActiveView('browser');
        const page = await generateMockPage(step.action.payload);
        if (page.title === "Error Loading Page") throw new Error("Simulation site unreachable.");
        setBrowserPage(page);
      }

      if (step.action.type === 'FILE_NAVIGATE') {
        setActiveView('filesystem');
      }

      if (step.action.type === 'TERMINAL_COMMAND') {
        setActiveView('terminal');
      }

      await new Promise(resolve => setTimeout(resolve, duration));

      setMessages(prev => prev.map(m => ({
        ...m,
        steps: m.steps?.map(s => s.id === step.id ? { ...s, action: { ...s.action, status: 'success' as const } } : s)
      })));

      setCurrentAction(null);
      return true;
    } catch (error: any) {
      console.error("Step execution failed:", error);
      setMessages(prev => prev.map(m => ({
        ...m,
        steps: m.steps?.map(s => s.id === step.id ? { ...s, action: { ...s.action, status: 'failed' as const } } : s)
      })));
      setCurrentAction(null);
      throw error;
    }
  };

  const executeWorkflow = async (steps: AgentStep[]) => {
    try {
      for (const step of steps) {
        if (step.requiresConfirmation) {
          setStatus(AgentStatus.WAITING_FOR_USER);
          setCurrentStepId(step.id);
          return;
        }
        await executeStep(step);
      }
      setStatus(AgentStatus.IDLE);
      setCurrentStepId(undefined);
    } catch (error: any) {
      setStatus(AgentStatus.ERROR);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: `Workflow execution halted: ${error.message || 'Unknown internal error.'}`,
        timestamp: Date.now(),
        isError: true
      }]);
    }
  };

  const handleSendMessage = async (content: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setStatus(AgentStatus.THINKING);

    try {
      const result = await processUserIntent(content, messages);

      const workflowSteps: AgentStep[] = (result.steps || []).map((s: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        thought: s.thought,
        action: {
          id: Math.random().toString(36).substr(2, 9),
          ...s.action,
          status: 'pending',
          timestamp: Date.now()
        },
        requiresConfirmation: s.action.requiresConfirmation
      }));

      const agentMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'agent',
        content: result.content || (result.intent === 'WORKFLOW' ? `Goal identified. Accessing necessary resources...` : "I'm on it."),
        isThinking: !!result.isThinking,
        isAutonomous: result.intent === 'WORKFLOW',
        groundingSources: result.sources || [],
        steps: workflowSteps,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, agentMsg]);

      if (result.intent === 'WORKFLOW' && workflowSteps.length > 0) {
        setStatus(AgentStatus.PLANNING);
        await new Promise(resolve => setTimeout(resolve, 1000));
        await executeWorkflow(workflowSteps);
      } else {
        setStatus(AgentStatus.IDLE);
      }
    } catch (error: any) {
      console.error(error);
      setStatus(AgentStatus.ERROR);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: error.message || 'Autonomous Kernel Error: Failed to sequence task list.',
        timestamp: Date.now(),
        isError: true
      }]);
    }
  };

  const handleApproveAction = async () => {
    const lastMsg = [...messages].reverse().find(m => m.steps && m.steps.length > 0);
    if (!lastMsg || !lastMsg.steps) return;

    const pendingSteps = lastMsg.steps.filter(s => s.action.status === 'pending');
    if (pendingSteps.length > 0) {
      await executeWorkflow(pendingSteps);
    }
  };

  const handleCancelAction = () => {
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);
    setCurrentStepId(undefined);
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'system',
      content: 'Autonomous workflow suspended by operator.',
      timestamp: Date.now()
    }]);
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden select-none">
      <Sidebar activeView={activeView} onViewChange={setActiveView} />
      <main className="flex-1 flex flex-col min-w-0">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/40 backdrop-blur-xl sticky top-0 z-50">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <div className={`w-2.5 h-2.5 rounded-full shadow-[0_0_12px_rgba(99,102,241,0.8)] animate-pulse ${status === AgentStatus.ERROR ? 'bg-red-500' : 'bg-indigo-500'}`}></div>
              <h1 className="text-sm font-bold text-slate-200 tracking-tight">NEXUS_ENV_AUTO_V1</h1>
            </div>
            <div className="h-4 w-px bg-slate-800"></div>
            <div className="flex gap-2">
              <span className={`text-[10px] px-2 py-0.5 rounded border font-bold uppercase tracking-wider ${status === AgentStatus.ERROR ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'}`}>
                {status === AgentStatus.ERROR ? 'Interrupt Active' : 'Autonomous Active'}
              </span>
            </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="text-right">
              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest leading-none mb-1">Compute Load</p>
              <div className="w-24 h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full transition-all duration-1000 ${status === AgentStatus.ERROR ? 'bg-red-500 w-full' : status !== AgentStatus.IDLE ? 'bg-indigo-50 w-3/4' : 'bg-indigo-500 w-1/4'}`}></div>
              </div>
            </div>
            <button 
              onClick={() => window.location.reload()}
              className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 text-[11px] font-bold rounded-lg transition-all border border-slate-700 active:scale-95">
              Reset Session
            </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
          <VirtualLaptop 
            activeView={activeView}
            currentAction={currentAction} 
            pageContent={browserPage}
            onManualNavigate={handleManualNavigate}
            onViewChange={setActiveView}
          />
          <AgentControl 
            messages={messages} 
            status={status}
            currentStepId={currentStepId}
            onSendMessage={handleSendMessage}
            onApproveAction={handleApproveAction}
            onCancelAction={handleCancelAction}
          />
        </div>
      </main>
    </div>
  );
};

export default App;
